package app.org.apache.roller.weblogger.webservices.oauth;

public class AuthorizationServlet extends HttpServlet { protected static Log log = LogFactory . getFactory ( ) . getInstance ( AuthorizationServlet . class ) ; @ Override public void doGet ( HttpServletRequest request , HttpServletResponse response ) throws IOException , ServletException { try { OAuthMessage requestMessage = OAuthServlet . getMessage ( request , null ) ; OAuthManager omgr = WebloggerFactory . getWeblogger ( ) . getOAuthManager ( ) ; OAuthAccessor accessor = omgr . getAccessor ( requestMessage ) ; if ( Boolean . TRUE . equals ( accessor . getProperty ( "authorized" ) ) ) { returnToConsumer ( request , response , accessor ) ; } else { sendToAuthorizePage ( request , response , accessor ) ; } } catch ( Exception e ) { handleException ( e , request , response , true ) ; } } @ Override public void doPost ( HttpServletRequest request , HttpServletResponse response ) throws IOException , ServletException { try { OAuthMessage requestMessage = OAuthServlet . getMessage ( request , null ) ; OAuthManager omgr = WebloggerFactory . getWeblogger ( ) . getOAuthManager ( ) ; OAuthAccessor accessor = omgr . getAccessor ( requestMessage ) ; String userId = request . getParameter ( "userId" ) ; if ( userId == null ) { userId = request . getParameter ( "xoauth_requestor_id" ) ; } if ( userId == null ) { sendToAuthorizePage ( request , response , accessor ) ; } else { String consumerUserId = ( String ) accessor . consumer . getProperty ( "userId" ) ; if ( consumerUserId != null && ! userId . equals ( consumerUserId ) ) { throw new ServletException ( "ERROR: invalid or unspecified userId" ) ; } omgr . markAsAuthorized ( accessor , userId ) ; WebloggerFactory . getWeblogger ( ) . flush ( ) ; } returnToConsumer ( request , response , accessor ) ; } catch ( Exception e ) { handleException ( e , request , response , true ) ; } } private void sendToAuthorizePage ( HttpServletRequest request , HttpServletResponse response , OAuthAccessor accessor ) throws IOException , ServletException { String callback = request . getParameter ( "oauth_callback" ) ; if ( callback == null || callback . length ( ) <= 0 ) { callback = "none" ; } String consumer_description = ( String ) accessor . consumer . getProperty ( "description" ) ; request . setAttribute ( "CONS_DESC" , consumer_description ) ; request . setAttribute ( "CALLBACK" , callback ) ; request . setAttribute ( "TOKEN" , accessor . requestToken ) ; request . getRequestDispatcher ( "/roller-ui/oauthAuthorize.rol" ) . forward ( request , response ) ; } private void returnToConsumer ( HttpServletRequest request , HttpServletResponse response , OAuthAccessor accessor ) throws IOException , ServletException { String callback = request . getParameter ( "oauth_callback" ) ; if ( "none" . equals ( callback ) && accessor . consumer . callbackURL != null && accessor . consumer . callbackURL . length ( ) > 0 ) { callback = accessor . consumer . callbackURL ; } if ( "none" . equals ( callback ) ) { response . setContentType ( "text/plain" ) ; PrintWriter out = response . getWriter ( ) ; out . println ( "You have successfully authorized for consumer key '" + accessor . consumer . consumerKey + "'. Please close this browser window and click continue" + " in the client." ) ; out . close ( ) ; } else { if ( callback == null || callback . length ( ) <= 0 ) { callback = accessor . consumer . callbackURL ; } String token = accessor . requestToken ; if ( token != null && callback != null ) { callback = OAuth . addParameters ( callback , "oauth_token" , token ) ; } response . setStatus ( HttpServletResponse . SC_MOVED_TEMPORARILY ) ; response . setHeader ( "Location" , callback ) ; } } public void handleException ( Exception e , HttpServletRequest request , HttpServletResponse response , boolean sendBody ) throws IOException , ServletException { log . debug ( "ERROR authorizing token" , e ) ; String realm = ( request . isSecure ( ) ) ? "https://" : "http://" ; realm += request . getLocalName ( ) ; OAuthServlet . handleException ( response , e , realm , sendBody ) ; } }